    """
    Find the first line which matches a pattern

    Parameters
    ----------
    lines : list
        List of strings
    latex : str
        Search pattern

    Returns
    -------
    line_num : int, None
        Line number. Returns None, if no match was found

    """
    re_string = re.compile(latex.replace("\\", "\\\\"))
    for i, line in enumerate(lines):
